import { getReq } from '@meli/server-context';
import { parseCookieValue } from '@nordic/utils/cookie';

import {
  DC_COOKIE,
  DC_COOKIE_DICTIONARY,
  DEVICE_CAPABILITIES_GROUPS_DICTIONARY,
} from './constants';
import { getDeviceOSFromWebview } from './os';

type Profile = {
  deviceInfo?: Record<string, Record<string, unknown>>;
  networkState?: Record<string, Record<string, unknown>>;
};

export function getProfileWithWebkitCookieInfo() {
  const cookieValue = getReq().cookies[DC_COOKIE];
  const os = getDeviceOSFromWebview();
  const profile: Profile = os ? { deviceInfo: { os } } : {};

  if (!cookieValue) {
    return profile;
  }

  const parsedValue = parseCookieValue(cookieValue, DC_COOKIE_DICTIONARY);

  return Object.entries(parsedValue).reduce((acc, [key, value]) => {
    const group = DEVICE_CAPABILITIES_GROUPS_DICTIONARY[key];

    if (!group) {
      return acc;
    }

    const { main: mainGroup, subs: subgroups, formatter } = group;

    if (!acc[mainGroup]) {
      acc[mainGroup] = {};
    }

    let profileBlock: Record<string, unknown> = acc[mainGroup];

    subgroups?.forEach((subgroup) => {
      profileBlock[subgroup] = profileBlock[subgroup] || {};
      profileBlock = profileBlock[subgroup] as Record<string, unknown>;
    });
    profileBlock[key] =
      typeof value === 'string' && typeof formatter === 'function'
        ? formatter(value)
        : value;

    return acc;
  }, profile);
}
